using System;
using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models; // Adjust namespace as needed
using System.Text.RegularExpressions;

namespace YourNamespace.Controllers
{
    public class ReviewsController : Controller
    {
        private readonly ApplicationDbContext _db = new ApplicationDbContext();

        public ActionResult Index(int productId)
        {
            var reviews = _db.Reviews.Where(r => r.ProductId == productId).ToList();
            return View(reviews);
        }

        [HttpPost]
        public ActionResult AddReview(int productId, string content)
        {
            var review = new Review
            {
                ProductId = productId,
                Content = SanitizeReviewContent(content),
                DateCreated = DateTime.Now
            };

            _db.Reviews.Add(review);
            _db.SaveChanges();

            return RedirectToAction("Index", new { productId });
        }

        private string SanitizeReviewContent(string content)
        {
            var allowedTags = new[] { "b", "i" };
            var allowedTagsPattern = string.Join("|", allowedTags);
            var regex = new Regex($@"<(?!(?:{allowedTagsPattern})\b)[^>]*>", RegexOptions.IgnoreCase);
            return regex.Replace(content, string.Empty);
        }
    }
}

@* Razor View (Index.cshtml) *@
@model List<YourNamespace.Models.Review> // Adjust namespace as needed

<h2>Product Reviews</h2>
@foreach (var review in Model)
{
    <div class="review">
        <div>@Html.Raw(review.Content)</div>
        <small>Posted on: @review.DateCreated.ToString("g")</small>
    </div>
}

<form action="@Url.Action("AddReview", "Reviews")" method="post">
    <input type="hidden" name="productId" value="@ViewBag.ProductId" />
    <textarea name="content" rows="4" cols="50"></textarea><br />
    <input type="submit" value="Submit Review" />
</form>